import React, { useEffect, useState } from 'react';
import { HashRouter as Router, Routes, Route } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import ErrorBoundary from './components/ErrorBoundary';
import Navbar from './components/Navbar';
import Home from './components/Home';
import About from './components/About';
import Products from './components/Products';
import Gallery from './components/Gallery';
import Contact from './components/Contact';
import Footer from './components/Footer';
import { MessageCircle, X, Send, Sparkles } from 'lucide-react';
import './index.css';

/**
 * Floating Chat Widget (100% static, no backend)
 */
const FloatingChat = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [step, setStep] = useState('welcome'); // welcome | form | sent
  const [name, setName] = useState('');
  const [phone, setPhone] = useState('');
  const [query, setQuery] = useState('');
  const [loading, setLoading] = useState(false);
  const [sent, setSent] = useState(false);

  const quickQueries = [
    "LED Sign Board Price?",
    "ACP Glow Sign Board",
    "3D Acrylic Letters",
    "Custom Name Plate",
    "Full Catalogue PDF",
    "Shop Front Signage"
  ];

  const handleQuick = (text) => {
    setQuery(text);
    setStep('form');
  };

  const handleSend = () => {
    if (!name || !phone) return;
    setLoading(true);

    // Simulate sending (you can later connect EmailJS here)
    setTimeout(() => {
      setLoading(false);
      setSent(true);
      setTimeout(() => {
        setIsOpen(false);
        setTimeout(() => {
          setStep('welcome');
          setName('');
          setPhone('');
          setQuery('');
          setSent(false);
        }, 500);
      }, 2500);
    }, 1500);
  };

  return (
    <>
      {/* Floating Button */}
      <motion.div
        initial={{ scale: 0 }}
        animate={{ scale: 1 }}
        transition={{ delay: 1.5, type: "spring" }}
        className="fixed z-50 bottom-6 right-6"
      >
        <motion.button
          onClick={() => setIsOpen(!isOpen)}
          whileHover={{ scale: 1.15 }}
          whileTap={{ scale: 0.95 }}
          className="relative flex items-center justify-center w-16 h-16 text-white rounded-full shadow-2xl bg-gradient-to-br from-blue-600 to-blue-800"
        >
          {isOpen ? <X size={32} /> : <MessageCircle size={34} />}
          {!isOpen && (
            <motion.div
              animate={{ scale: [1, 1.3, 1] }}
              transition={{ repeat: Infinity, duration: 4 }}
              className="absolute w-5 h-5 bg-green-500 border-4 border-white rounded-full -top-1 -right-1"
            />
          )}
        </motion.button>
      </motion.div>

      {/* Chat Window */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 20, scale: 0.9 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 20, scale: 0.9 }}
            className="fixed z-50 overflow-hidden bg-white border border-gray-200 shadow-2xl bottom-24 right-6 w-80 sm:w-96 rounded-2xl"
          >
            {/* Header */}
            <div className="p-4 text-white bg-gradient-to-r from-blue-600 to-blue-700">
              <div className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="flex items-center justify-center w-10 h-10 rounded-full bg-white/20">
                    <Sparkles size={20} />
                  </div>
                  <div>
                    <h3 className="font-bold">India Advertising</h3>
                    <p className="text-xs opacity-90">We reply in minutes!</p>
                  </div>
                </div>
                <button onClick={() => setIsOpen(false)} className="p-1 rounded hover:bg-white/20">
                  <X size={20} />
                </button>
              </div>
            </div>

            <div className="p-5 space-y-4 overflow-y-auto h-96 bg-gray-50">
              {step === 'welcome' && (
                <>
                  <div className="bg-white rounded-2xl p-4 shadow-sm max-w-[80%]">
                    <p className="font-medium">Namaste! Welcome</p>
                    <p className="mt-1 text-sm text-gray-600">How can we help you today?</p>
                  </div>

                  <div className="grid grid-cols-1 gap-3 mt-4">
                    {quickQueries.map((q) => (
                      <button
                        key={q}
                        onClick={() => handleQuick(q)}
                        className="p-3 text-sm font-medium text-left transition-all bg-white border border-gray-200 hover:bg-blue-50 rounded-xl hover:shadow-md"
                      >
                        {q}
                      </button>
                    ))}
                  </div>
                </>
              )}

              {step === 'form' && (
                <>
                  <div className="bg-blue-100 rounded-2xl p-4 max-w-[80%] ml-auto shadow-sm">
                    <p className="text-sm font-medium">{query}</p>
                  </div>

                  <div className="bg-white rounded-2xl p-4 shadow-sm max-w-[80%]">
                    <p className="text-sm">Perfect! Please share your details. We’ll call you in 5 mins</p>
                  </div>

                  <input
                    type="text"
                    placeholder="Your Name"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    className="w-full px-4 py-3 mt-3 border border-gray-300 outline-none rounded-xl focus:border-blue-500"
                  />
                  <input
                    type="tel"
                    placeholder="Mobile Number"
                    value={phone}
                    onChange={(e) => setPhone(e.target.value)}
                    className="w-full px-4 py-3 border border-gray-300 outline-none rounded-xl focus:border-blue-500"
                  />
                </>
              )}

              {step === 'sent' && sent && (
                <motion.div initial={{ scale: 0.8 }} animate={{ scale: 1 }} className="py-12 text-center">
                  <div className="flex items-center justify-center w-20 h-20 mx-auto bg-green-100 rounded-full">
                    <span className="text-5xl">Checkmark</span>
                  </div>
                  <p className="mt-4 text-lg font-bold text-green-600">Thank You!</p>
                  <p className="text-gray-600">We’ll contact you shortly</p>
                </motion.div>
              )}
            </div>

            {step === 'form' && (
              <div className="p-4 bg-white border-t">
                <button
                  onClick={handleSend}
                  disabled={!name || !phone || loading}
                  className="flex items-center justify-center w-full gap-2 py-3 font-bold text-white transition bg-gradient-to-r from-blue-600 to-blue-700 rounded-xl disabled:opacity-50"
                >
                  {loading ? "Sending..." : <>Send Request <Send size={18} /></>}
                </button>
              </div>
            )}
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
};

/**
 * MainPage Component
 */
function MainPage() {
  return (
    <div className="relative min-h-screen bg-white">
      <Navbar />
      <motion.main
        initial="hidden"
        animate="visible"
        variants={{ 
          visible: { transition: { staggerChildren: 0.1, delayChildren: 0.2 } } 
        }}
        role="main"
      >
        <Home />
        <About />
        <Products />
        <Gallery />
        <Contact />
      </motion.main>
      <Footer />

      {/* Add the Floating Chat Here */}
      <FloatingChat />
    </div>
  );
}

/**
 * App Component
 */
function App() {
  useEffect(() => {
    document.documentElement.classList.remove('dark');
    localStorage.setItem('theme', 'light');
    document.title = 'India Advertising | Premium Advertising Solutions';

    const metaDescription = document.querySelector('meta[name="description"]');
    if (!metaDescription) {
      const meta = document.createElement('meta');
      meta.name = 'description';
      meta.content = 'India Advertising - Premium SS Name Plates, Acrylic Signs, LED Boards, and advertising solutions across India.';
      document.head.appendChild(meta);
    }
  }, []);

  return (
    <ErrorBoundary>
      <Router>
        <Routes>
          <Route path="/" element={<MainPage />} />
          <Route path="*" element={<MainPage />} />
        </Routes>
      </Router>
    </ErrorBoundary>
  );
}

export default App;
